import React from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { ReactComponent as PhotoAutomatSVG } from "../public/photoautomat.svg"; // นำเข้าไฟล์ SVG
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* ✅ เพิ่ม SVG ของโคมไฟแทนที่รูป photobooth1.png */}
      <div className="lantern-container">
        <PhotoAutomatSVG className="photoautomat-svg" />
      </div>

      {/* 📌 เนื้อหาหน้า Home */}
      <div className="home-container mt-24">
        <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>
        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>

        {/* ✅ ใช้ Framer Motion ทำให้เลเยอร์ "light" กระพริบ */}
        <motion.g
          id="light"
          animate={{ fill: ["#e7e5d5", "#ffe966", "#e7e5d5"] }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        />

        <button onClick={() => navigate("/welcome")} className="start-button">
          START
        </button>

        <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
      </div>
    </div>
  );
};

export default Home;
